-- ============================================================
-- TRIGGERS
-- ============================================================

-- Auto-update updated_at on signals table
CREATE TRIGGER IF NOT EXISTS trg_signals_updated_at
    AFTER UPDATE ON signals
    FOR EACH ROW
BEGIN
    UPDATE signals SET updated_at = datetime('now') WHERE id = OLD.id;
END;
